package ir.tahamohamadi.skill; import ir.tahamohamadi.common.domain.LanguageCode; import ir.tahamohamadi.common.persistence.AuditedSoftDeletableEntity; import jakarta.persistence.*; import lombok.*;
@Entity @Table(name="skill_translation") @Getter @NoArgsConstructor(access=AccessLevel.PROTECTED) public class SkillTranslation extends AuditedSoftDeletableEntity { @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="skill_id",nullable=false) private Skill skill; @Enumerated(EnumType.STRING) @Column(name="language_code",nullable=false,length=2) private LanguageCode languageCode; @Column(nullable=false) private String name; @Column(columnDefinition="text") private String description; private SkillTranslation(java.util.UUID id,Skill skill,LanguageCode language,String name,String description,java.time.Instant at){initialize(id,at);this.skill=java.util.Objects.requireNonNull(skill);languageCode=java.util.Objects.requireNonNull(language);this.name=requireNonBlank(name,"name");this.description=description;} public static SkillTranslation create(java.util.UUID id,Skill skill,LanguageCode language,String name,String description,java.time.Instant at){return new SkillTranslation(id,skill,language,name,description,at);} public void update(String name,String description){this.name=requireNonBlank(name,"name");this.description=description;updatedAt=java.time.Instant.now();} }
